import { Input } from '@/Components/ui/input';
import { Label } from '@/Components/ui/label';
import { FormEventHandler } from 'react';

export default function Register() {
    const { data, setData, post, processing, errors, reset } = useForm({
        name: '',
        email: '',
        password: '',
        password_confirmation: '',
    });

    const submit: FormEventHandler = (e) => {
        e.preventDefault();

        post(route('register'), {
            onFinish: () => reset('password', 'password_confirmation'),
        });
    };

    return (
        <GuestLayout>
            <Head title="Sign Up" />

            <h2 className={cn('text-xl font-semibold text-foreground mb-6')}>Sign Up</h2>

            <form onSubmit={submit} className={cn('space-y-4')}>
                <div className={cn('space-y-2')}>
                    <Label htmlFor="name">Name</Label>
                    <Input
                        id="name"
                        value={data.name}
                        autoComplete="name"
                        autoFocus
                        onChange={(e) => setData('name', e.target.value)}
                        required
                    />
                    {errors.name && (
                        <p className={cn('text-sm text-destructive')}>{errors.name}</p>
                    )}
                </div>

                <div className={cn('space-y-2')}>
                    <Label htmlFor="email">Email</Label>
                    <Input
                        id="email"
                        type="email"
                        value={data.email}
                        autoComplete="username"
                        onChange={(e) => setData('email', e.target.value)}
                        required
                    />
                    {errors.email && (
                        <p className={cn('text-sm text-destructive')}>{errors.email}</p>
                    )}
                </div>

                <div className={cn('space-y-2')}>
                    <Label htmlFor="password">Password</Label>
                    <Input
                        id="password"
                        type="password"
                        value={data.password}
                        autoComplete="new-password"
                        onChange={(e) => setData('password', e.target.value)}
                        required
                    />
                    {errors.password && (
                        <p className={cn('text-sm text-destructive')}>{errors.password}</p>
                    )}
                </div>

                <div className={cn('space-y-2')}>
                    <Label htmlFor="password_confirmation">Confirm Password</Label>
                    <Input
                        id="password_confirmation"
                        type="password"
                        value={data.password_confirmation}
                        autoComplete="new-password"
                        onChange={(e) => setData('password_confirmation', e.target.value)}
                        required
                    />
                    {errors.password_confirmation && (
                        <p className={cn('text-sm text-destructive')}>{errors.password_confirmation}</p>
                    )}
                </div>

                <div className={cn('flex items-center justify-end pt-2')}>
                    <Button
                        type="submit"
                        disabled={processing}
                        className={cn('bg-brand-orange text-white hover:bg-brand-orange/90')}
                    >
                        Sign Up
                    </Button>
                </div>

                <p className={cn('text-center text-sm text-muted-foreground')}>
                    Already have an account?{' '}
                    <Link href={route('login')} className={cn('text-brand-orange hover:underline')}>
                        Sign In
                    </Link>
                </p>
            </form>
        </GuestLayout>
    );
}

