 10→
 11→interface BookingWizardProps {
 12→  propertyData: PropertyData;
 13→  auth: { user: User | null };
 14→}
 15→
 16→const STEPS = [
 17→  { number: 1, label: 'Dates' },
 18→  { number: 2, label: 'Rooms' },
 19→  { number: 3, label: 'Summary' },
 20→  { number: 5, label: 'Status' },
 21→] as const;
 22→
 23→export function BookingWizard({ propertyData, auth }: BookingWizardProps) {
 24→  const currentStep = useBookingStore((s) => s.currentStep);
 25→  const goToStep = useBookingStore((s) => s.goToStep);
 26→  const stepContainerRef = useRef<HTMLDivElement>(null);
 27→
 28→  // Focus management on step change
 29→  useEffect(() => {
 30→    stepContainerRef.current?.focus();
 31→  }, [currentStep]);
 32→
 33→  return (
 34→    <div className={cn('mx-auto w-full max-w-3xl space-y-8')}>
 35→      {/* Step indicator */}
 36→      <nav aria-label="Booking progress" className={cn('rounded-xl p-4')}>
 37→        <ol className={cn('flex items-center')}>
 38→          {STEPS.map(({ number, label }, index) => {
 39→            const displayNumber = number === 5 ? 4 : number;
 40→            const isActive = currentStep === number;
 41→            const isCompleted = currentStep > number;
 42→
 43→            return (
 44→              <li key={number} className={cn('flex items-center', index < STEPS.length - 1 && 'flex-1')}>
 45→                <button
 46→                  type="button"
 47→                  onClick={() => isCompleted && goToStep(number)}
 48→                  disabled={!isCompleted}
 49→                  className={cn(
 50→                    'flex items-center gap-2 rounded-full px-1 py-1 transition-colors sm:pr-3',
 51→                    isActive && 'bg-primary/10',
 52→                    isCompleted && 'cursor-pointer hover:bg-primary/10'
 53→                  )}
 54→                >
 55→                  <div
 56→                    className={cn(
 57→                      'flex h-9 w-9 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors',
 58→                      isActive && 'border-primary bg-primary text-primary-foreground shadow-sm',
 59→                      isCompleted && 'border-primary bg-primary text-primary-foreground',
 60→                      !isActive && !isCompleted && 'border-gray-300 bg-gray-200 text-gray-400'
 61→                    )}
 62→                    aria-current={isActive ? 'step' : undefined}
 63→                    aria-label={`Step ${displayNumber}: ${label}${isCompleted ? ' (completed)' : ''}${isActive ? ' (current)' : ''}`}
 64→                  >
 65→                    {isCompleted ? (
 66→                      <svg className={cn('h-4 w-4')} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
 67→                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
 68→                      </svg>
 69→                    ) : (
 70→                      displayNumber
 71→                    )}
 72→                  </div>
 73→                  <span
 74→                    className={cn(
 75→                      'hidden text-sm sm:inline',
 76→                      isActive && 'font-semibold text-foreground',
 77→                      isCompleted && 'font-medium text-primary',
 78→                      !isActive && !isCompleted && 'text-gray-400'
 79→                    )}
 80→                  >
 81→                    {label}
 82→                  </span>
 83→                </button>
 84→                {/* Connector line between steps */}
 85→                {index < STEPS.length - 1 && (
 86→                  <div
 87→                    className={cn(
 88→                      'mx-3 hidden h-0.5 flex-1 rounded-full sm:block',
 89→                      isCompleted ? 'bg-primary' : 'bg-muted-foreground/20'
 90→                    )}
 91→                    aria-hidden="true"
 92→                  />
 93→                )}
 94→              </li>
 95→            );
 96→          })}
 97→        </ol>
 98→        {/* Progress bar */}
 99→        <div className={cn('mt-3 h-1.5 w-full overflow-hidden rounded-full bg-muted')} aria-hidden="true">
100→          <div
101→            className={cn('h-full rounded-full bg-primary transition-all duration-300')}
102→            style={{
