 1→import { useState, useEffect, useRef, useCallback } from 'react';
 2→import axios from 'axios';
 3→import type { BookingStatus, BookingStatusResponse } from '@/types/booking';
 4→
 5→const POLL_INTERVAL_MS = 2500;
 6→const TIMEOUT_MS = 60000;
 7→
 8→interface UseBookingStatusResult {
 9→  status: BookingStatus | null;
10→  confirmationId: string | null;
11→  isPolling: boolean;
12→}
13→
14→export function useBookingStatus(bookingId: number | null): UseBookingStatusResult {
15→  const [status, setStatus] = useState<BookingStatus | null>(null);
16→  const [confirmationId, setConfirmationId] = useState<string | null>(null);
17→  const [isPolling, setIsPolling] = useState(false);
18→  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
19→  const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
20→
21→  const stopPolling = useCallback(() => {
22→    if (intervalRef.current) {
23→      clearInterval(intervalRef.current);
24→      intervalRef.current = null;
25→    }
26→    if (timeoutRef.current) {
27→      clearTimeout(timeoutRef.current);
28→      timeoutRef.current = null;
29→    }
30→    setIsPolling(false);
31→  }, []);
32→
33→  useEffect(() => {
34→    if (!bookingId) return;
35→
36→    setIsPolling(true);
37→    setStatus('pending');
38→
39→    const poll = async () => {
40→      try {
41→        const { data } = await axios.get<BookingStatusResponse>(
42→          `/api/bookings/${bookingId}/status`
43→        );
44→        setStatus(data.status);
45→        if (data.confirmation_id) {
46→          setConfirmationId(data.confirmation_id);
47→        }
48→        if (data.status === 'confirmed' || data.status === 'failed') {
49→          stopPolling();
50→        }
51→      } catch {
52→        // Keep polling on network errors - the server might be temporarily unavailable
53→      }
54→    };
55→
56→    // Poll immediately, then on interval
57→    poll();
58→    intervalRef.current = setInterval(poll, POLL_INTERVAL_MS);
59→
60→    // Safety timeout to prevent infinite polling
61→    timeoutRef.current = setTimeout(() => {
62→      stopPolling();
63→      setStatus('failed');
64→    }, TIMEOUT_MS);
65→
66→    return stopPolling;
67→  }, [bookingId, stopPolling]);
68→
69→  return { status, confirmationId, isPolling };
70→}
