 1→import { z } from 'zod';
 2→import { roomSelectionSchema } from './roomSchema';
 3→
 4→export const bookingSchema = z
 5→  .object({
 6→    checkIn: z.string().min(1, 'Check-in date is required'),
 7→    checkOut: z.string().min(1, 'Check-out date is required'),
 8→    rooms: z
 9→      .array(roomSelectionSchema)
10→      .refine((rooms) => rooms.some((r) => r.quantity > 0), {
