347→      <div className={cn('flex justify-between')}>
348→        <Button type="button" variant="outline" size="lg" onClick={prevStep}>
349→          Back
350→        </Button>
351→        <Button type="submit" size="lg">
352→          Next: Review Booking
353→        </Button>
354→      </div>
355→    </form>
356→  );
357→}
