 1→import { create } from 'zustand';
 2→import { persist } from 'zustand/middleware';
 3→
 4→export interface RoomSelection {
 5→  unitId: number;
 6→  quantity: number;
 7→  guests: number;
 8→  guestsPerRoom?: number[];
 9→}
10→
11→interface BookingState {
12→  currentStep: number;
13→  checkIn: string | null;
14→  checkOut: string | null;
15→  rooms: RoomSelection[];
16→  specialRequests: string;
17→  bookingId: number | null;
18→}
19→
20→interface BookingActions {
21→  setDates: (checkIn: string, checkOut: string) => void;
22→  setRooms: (rooms: RoomSelection[]) => void;
23→  setSpecialRequests: (requests: string) => void;
24→  setBookingId: (id: number) => void;
25→  nextStep: () => void;
26→  prevStep: () => void;
27→  goToStep: (step: number) => void;
28→  reset: () => void;
29→}
30→
31→const initialState: BookingState = {
32→  currentStep: 1,
33→  checkIn: null,
34→  checkOut: null,
35→  rooms: [],
36→  specialRequests: '',
37→  bookingId: null,
38→};
39→
40→export const useBookingStore = create<BookingState & BookingActions>()(
41→  persist(
42→    (set) => ({
43→      ...initialState,
44→      setDates: (checkIn, checkOut) => set({ checkIn, checkOut }),
45→      setRooms: (rooms) => set({ rooms }),
46→      setSpecialRequests: (specialRequests) => set({ specialRequests }),
47→      setBookingId: (bookingId) => set({ bookingId }),
48→      nextStep: () => set((state) => ({ currentStep: Math.min(state.currentStep + 1, 5) })),
49→      prevStep: () => set((state) => ({ currentStep: Math.max(state.currentStep - 1, 1) })),
50→      goToStep: (step) => set({ currentStep: step }),
51→      reset: () => set(initialState),
52→    }),
53→    { name: 'booking-wizard' }
54→  )
55→);
