 65→                      !field.value && 'text-muted-foreground'
 66→                    )}
 67→                    aria-label="Select check-in date"
 68→                    aria-invalid={!!errors.checkIn}
 69→                  >
 70→                    <CalendarIcon className={cn('mr-2 h-4 w-4')} />
 71→                    {field.value
 72→                      ? format(new Date(field.value), 'PPP')
 73→                      : 'Select date'}
 74→                  </Button>
 75→                </PopoverTrigger>
 76→                <PopoverContent className={cn('w-auto p-0')} align="start">
 77→                  <Calendar
 78→                    mode="single"
 79→                    selected={field.value ? new Date(field.value) : undefined}
 80→                    onSelect={(date) => {
 81→                      field.onChange(date ? format(date, 'yyyy-MM-dd') : '');
 82→                    }}
 83→                    disabled={{ before: today }}
 84→                    autoFocus
 85→                  />
 86→                </PopoverContent>
 87→              </Popover>
 88→            )}
 89→          />
 90→          {errors.checkIn && (
 91→            <p className={cn('text-sm text-destructive')} role="alert">
 92→              {errors.checkIn.message}
 93→            </p>
 94→          )}
 95→        </div>
 96→
 97→        {/* Check-out date picker */}
 98→        <div className={cn('space-y-2')}>
 99→          <Label htmlFor="checkOut">Check-out</Label>
100→          <Controller
101→            control={control}
102→            name="checkOut"
103→            render={({ field }) => {
104→              const minCheckOut = watchedCheckIn
105→                ? addDays(new Date(watchedCheckIn), 1)
106→                : addDays(today, 1);
107→
108→              return (
109→                <Popover>
110→                  <PopoverTrigger asChild>
111→                    <Button
112→                      id="checkOut"
113→                      variant="outline"
114→                      size="lg"
115→                      className={cn(
116→                        'w-full justify-start text-left font-normal',
117→                        !field.value && 'text-muted-foreground'
118→                      )}
119→                      aria-label="Select check-out date"
120→                      aria-invalid={!!errors.checkOut}
121→                    >
122→                      <CalendarIcon className={cn('mr-2 h-4 w-4')} />
123→                      {field.value
124→                        ? format(new Date(field.value), 'PPP')
125→                        : 'Select date'}
126→                    </Button>
127→                  </PopoverTrigger>
128→                  <PopoverContent className={cn('w-auto p-0')} align="start">
129→                    <Calendar
130→                      mode="single"
131→                      selected={
132→                        field.value ? new Date(field.value) : undefined
133→                      }
134→                      onSelect={(date) => {
135→                        field.onChange(date ? format(date, 'yyyy-MM-dd') : '');
136→                      }}
137→                      disabled={{ before: minCheckOut }}
138→                      autoFocus
139→                    />
140→                  </PopoverContent>
141→                </Popover>
142→              );
143→            }}
144→          />
145→          {errors.checkOut && (
146→            <p className={cn('text-sm text-destructive')} role="alert">
147→              {errors.checkOut.message}
148→            </p>
149→          )}
150→        </div>
151→      </div>
152→
153→      {nights > 0 && (
154→        <p className={cn('text-sm text-muted-foreground')}>
155→          {nights} {nights === 1 ? 'night' : 'nights'} selected
156→        </p>
157→      )}
158→
159→      <div className={cn('flex justify-end')}>
160→        <Button type="submit" size="lg">
161→          Next: Select Rooms
