 1→import {
 2→    forwardRef,
 3→    InputHTMLAttributes,
 4→    useEffect,
 5→    useImperativeHandle,
 6→    useRef,
 7→} from 'react';
 8→
 9→export default forwardRef(function TextInput(
10→    {
11→        type = 'text',
12→        className = '',
13→        isFocused = false,
14→        ...props
15→    }: InputHTMLAttributes<HTMLInputElement> & { isFocused?: boolean },
16→    ref,
17→) {
18→    const localRef = useRef<HTMLInputElement>(null);
19→
20→    useImperativeHandle(ref, () => ({
21→        focus: () => localRef.current?.focus(),
22→    }));
23→
24→    useEffect(() => {
25→        if (isFocused) {
26→            localRef.current?.focus();
27→        }
28→    }, [isFocused]);
29→
30→    return (
31→        <input
32→            {...props}
33→            type={type}
34→            className={
35→                'rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 ' +
36→                className
37→            }
38→            ref={localRef}
39→        />
40→    );
41→});
