        {currentStep === 2 && <RoomStep propertyData={propertyData} />}
        {currentStep === 3 && <SummaryStep propertyData={propertyData} auth={auth} />}
        {currentStep === 5 && <StatusStep propertyData={propertyData} />}
      </div>
    </div>
  );
}

